+                }\n                 FftVisualizationMode::FullFft =\u003e {\n                     if analysis.beat_detected && i \u003c 2 {\n                         colors::MINT_ACCENT\n+                    } else if energy \u003e= 0.95 {\n+                        colors::ERROR_COLOR\n                     } else {\n                         colors::CYAN_ACCENT.linear_multiply(0.6 + (energy * 0.4))\n                     }\n",
