llowed_origins(),\n             auth: AuthConfig::new(),\n         }\n@@ -322,6 +322,12 @@ mod tests {\n         assert!(config.allowed_origins.is_empty());\n     }\n \n+    #[test]\n+    fn test_web_server_default_cors() {\n+        let config = WebServerConfig::default();\n+        assert!(!config.enable_cors);\n+    }\n+\n     #[test]\n     fn test_web_server_default_host() {\n         let config = WebServerConfig::default();\n",
