           let filter_bytes = filter_lower.as_bytes();\n+            let filter_is_empty = filter_lower.is_empty();\n             let matching_parts: Vec\u003c_\u003e = module\n                 .parts\n                 .iter()\n                 .filter(|p| {\n-                    if filter_bytes.is_empty() {\n+                    if filter_is_empty {\n                         return true;\n                     }\n                     let name = utils::get_part_property_text(&p.part_type);\n-                    let name_bytes = name.as_bytes();\n+                    if name.to_lowercase().contains(&filter_lower) {\n+                        return true;\n+                    }\n                     let (_, _, _, type_name) = utils::get_part_style(&p.part_type);\n-                    let type_name_bytes = type_name.as_bytes();\n-\n-                    (!name_bytes.is_empty()\n-                        && name_bytes.len() \u003e= filter_bytes.len()\n-                        && name_bytes\n-                            .windows(filter_bytes.len())\n-                            .any(|w| w.eq_ignore_ascii_case(filter_bytes)))\n-                        || (!type_name_bytes.is_empty()\n-                            && type_name_bytes.len() \u003e= filter_bytes.len()\n-                            && type_name_bytes\n-                                .windows(filter_bytes.len())\n-                                .any(|w| w.eq_ignore_ascii_case(filter_bytes)))\n+                    if type_name.to_lowercase().contains(&filter_lower) {\n+                        return true;\n+                    }\n+                    false\n                 })\n                 .take(6)\n                 .collect();\ndiff --git a/crates/vorce-ui/src/panels/shortcuts_panel.rs b/crates/vorce-ui/src/panels/shortcuts_panel.rs\nindex 498def1..6909650 100644\n--- a/crates/vorce-ui/src/panels/shortcuts_panel.rs\n+++ b/crates/vorce-ui/src/panels/shortcuts_panel.rs\n@@ -72,28 +72,22 @@ impl ShortcutsPanel {\n \n         // --- Filter and Group Shortcuts ---\n         let filter_lower = self.search_filter.to_lowercase();\n-        let filter_bytes = filter_lower.as_bytes();\n+        let filter_is_empty = filter_lower.is_empty();\n         let filtered_indices: Vec\u003cusize\u003e = shortcuts_clone\n             .iter()\n             .enumerate()\n             .filter(|(_, s)| {\n-                if filter_bytes.is_empty() {\n+                if filter_is_empty {\n+                    return true;\n+                }\n+                if s.description.to_lowercase().contains(&filter_lower) {\n                     return true;\n                 }\n-                let desc_bytes = s.description.as_bytes();\n                 let shortcut_str = s.to_shortcut_string();\n-                let shortcut_bytes = shortcut_str.as_bytes();\n-\n-                (!desc_bytes.is_empty()\n-                    && desc_bytes.len() \u003e= filter_bytes.len()\n-                    && desc_bytes\n-                        .windows(filter_bytes.len())\n-                        .any(|w| w.eq_ignore_ascii_case(filter_bytes)))\n-                    || (!shortcut_bytes.is_empty()\n-                        && shortcut_bytes.len() \u003e= filter_bytes.len()\n-                        && shortcut_bytes\n-                            .windows(filter_bytes.len())\n-                            .any(|w| w.eq_ignore_ascii_case(filter_bytes)))\n+                if shortcut_str.to_lowercase().contains(&filter_lower) {\n+                    return true;\n+                }\n+                false\n             })\n             .map(|(i, _)| i)\n             .collect();\n",
