              "unidiffPatch": "diff --git a/.jules/bolt.md b/.jules/bolt.md\nindex edb5ec5..a0c872d 100644\n--- a/.jules/bolt.md\n+++ b/.jules/bolt.md\n@@ -5,3 +5,6 @@\n ## 2025-03-25 - [Redundant String Allocation in Loops]\n **Learning:** Found a common pattern in UI filtering where `String::to_lowercase()` was called inside a `.filter()` iterator closure. This causes O(N) heap allocations during search operations, degrading UI performance with large media libraries.\n **Action:** Always pre-compute and cache string transformations like `to_lowercase()` in the corresponding models (e.g. `MediaItem`, `EffectPreset`, `MediaEntry`) instead of dynamically calling `to_lowercase()` inside `filter()` closures during UI searches. This significantly reduces allocations and speeds up query operations.\n+## 2025-03-25 - [Memory Leak with Box::leak in Dynamic GUI Structs]\n+**Learning:** Using `Box::leak` inside functions like `build_node_catalog()` to satisfy `&'static str` requirements for dynamically generated data causes severe memory leaks because the catalog is rebuilt frequently (potentially every frame) during immediate-mode GUI operations.\n+**Action:** Always use owned `String` fields instead of `&'static str` for fields that are derived or computed dynamically at runtime in structures built inside hot UI loops.\ndiff --git a/crates/vorce-ui/src/core/config.rs b/crates/vorce-ui/src/core/config.rs\nindex c74e23b..1fb3f62 100644\n--- a/crates/vorce-ui/src/core/config.rs\n+++ b/crates/vorce-ui/src/core/config.rs\n@@ -521,9 +521,7 @@ impl UserConfig {\n         })\n     }\n \n-    fn resolve_existing_config_path(\n-        primary: Option\u003cPathBuf\u003e,\n-    ) -\u003e Option\u003cPathBuf\u003e {\n+    fn resolve_existing_config_path(primary: Option\u003cPathBuf\u003e) -\u003e Option\u003cPathBuf\u003e {\n         primary.as_ref().filter(|path| path.exists()).cloned()\n     }\n \n@@ -785,6 +783,3 @@ mod tests {\n         assert!(!config.set_active_layout(\"does-not-exist\"));\n     }\n }\n-st\"));\n-    }\n-}\ndiff --git a/crates/vorce-ui/src/editors/module_canvas/draw/quick_create.rs b/crates/vorce-ui/src/editors/module_canvas/draw/quick_create.rs\nindex b7741f3..a6fbf34 100644\n--- a/crates/vorce-ui/src/editors/module_canvas/draw/quick_create.rs\n+++ b/crates/vorce-ui/src/editors/module_canvas/draw/quick_create.rs\n@@ -21,8 +21,7 @@ pub fn draw_quick_create_popup(\n             if filter_lower.is_empty() {\n                 true\n             } else {\n-                item.label.to_lowercase().contains(&filter_lower)\n-                    || item.search_tags.contains(&filter_lower)\n+                item.label_lower.contains(&filter_lower) || item.search_tags.contains(&filter_lower)\n             }\n         })\n         .collect();\ndiff --git a/crates/vorce-ui/src/editors/module_canvas/utils/catalog.rs b/crates/vorce-ui/src/editors/module_canvas/utils/catalog.rs\nindex bcac57a..79fd165 100644\n--- a/crates/vorce-ui/src/editors/module_canvas/utils/catalog.rs\n+++ b/crates/vorce-ui/src/editors/module_canvas/utils/catalog.rs\n@@ -8,10 +8,23 @@ use vorce_core::module::{\n pub struct NodeCatalogItem {\n     /// User-friendly name for identifying the element.\n     pub label: &'static str,\n+    /// Pre-lowercased label for faster allocations-free searching.\n+    pub label_lower: String,\n     pub search_tags: &'static str,\n     pub part_type: ModulePartType,\n }\n \n+impl NodeCatalogItem {\n+    pub fn new(label: &'static str, search_tags: &'static str, part_type: ModulePartType) -\u003e Self {\n+        Self {\n+            label,\n+            label_lower: label.to_lowercase(),\n+            search_tags,\n+            part_type,\n+        }\n+    }\n+}\n+\n pub fn build_node_catalog() -\u003e Vec\u003cNodeCatalogItem\u003e {\n     let shader_supported = capabilities::is_source_type_enum_supported(true, false, false, false);\n \n@@ -23,71 +36,71 @@ pub fn build_node_catalog() -\u003e Vec\u003cNodeCatalogItem\u003e {\n \n  