('')\n+            \n+        new_lines.append(line)\n+    return '\\n'.join(new_lines)\n+\n+\n+def process_file(filepath):\n+    with open(filepath, 'r') as f:\n+        content = f.read()\n+    \n+    # content = fix_table(content)\n+    # content = fix_list_blanks(content)\n+    \n+    # with open(filepath, 'w') as f:\n+    #    f.write(content)\n+\n+if __name__ == '__main__':\n+    for arg in sys.argv[1:]:\n+        process_file(arg)\ndiff --git a/format_tables.py b/format_tables.py\nnew file mode 100644\nindex 0000000..2a0dc10\n--- /dev/null\n+++ b/format_tables.py\n@@ -0,0 +1,61 @@\n+import re\n+\n+def format_file(filepath):\n+    with open(filepath, 'r') as f:\n+        lines = f.readlines()\n+\n+    out = []\n+    table_lines = []\n+    in_table = False\n+\n+    for line in lines:\n+        if line.strip().startswith('|'):\n+            table_lines.append(line.strip())\n+        else:\n+            if table_lines:\n+                out.extend(format_table(table_lines))\n+                table_lines = []\n+            out.append(line.rstrip('\\n'))\n+\n+    if table_lines:\n+        out.extend(format_table(table_lines))\n+\n+    with open(filepath, 'w') as f:\n+        f.write('\\n'.join(out) + '\\n')\n+\n+def format_table(lines):\n+    # parse\n+    parsed = []\n+    for line in lines:\n+        parts = [p.strip() for p in line.split('|')[1:-1]]\n+        parsed.append(parts)\n+\n+    # get widths\n+    widths = []\n+    for row in parsed:\n+        for i, part in enumerate(row):\n+            if len(widths) \u003c= i:\n+                widths.append(len(part))\n+            else:\n+                widths[i] = max(widths[i], len(part))\n+\n+    # set minimum width for header separator\n+    for i, w in enumerate(widths):\n+        widths[i] = max(w, 3)\n+\n+    formatted = []\n+    for r_idx, row in enumerate(parsed):\n+        new_row = []\n+        for i, part in enumerate(row):\n+            if r_idx == 1:\n+                # header separator line\n+                new_row.append('-' * widths[i])\n+            else:\n+                new_row.append(part.ljust(widths[i]))\n+        formatted.append('| ' + ' | '.join(new_row) + ' |')\n+    return formatted\n+\n+import sys\n+if __name__ == '__main__':\n+    for arg in sys.argv[1:]:\n+        format_file(arg)\n",
