ts.is_empty() {\n-                                    ui.label(locale.t(\"effect-no-presets\"));\n+                                    crate::widgets::custom::render_info_label(ui, &locale.t(\"effect-no-presets\"));\n                                 }\n                             });\n                     });\n",
